            print("Writing with a pen.")

    class Keyboard:
        def write(self):
            print("Typing with a keyboard.")

    def compose(writer):
        writer.write()

    pen = Pen()
    keyboard = Keyboard()

    compose(pen)       # Output: Writing with a pen.
    compose(keyboard)  # Output: Typing with a keyboard.



